}

'use client';

import { useState, useRef, useEffect } from 'react';
import { useAnamQaSession } from '@/hooks/useAnamQaSession';
import TranscriptPanel from './TranscriptPanel';
import { Send, Square, RefreshCcw, Hand } from 'lucide-react';

interface AgentQaChatProps {
    personaId: string;
    agentName: string;
}

export default function AgentQaChat({ personaId, agentName }: AgentQaChatProps) {
    const [inputValue, setInputValue] = useState('');
    const [isSending, setIsSending] = useState(false);

    const { 
        connectionState, 
        messages, 
        connect, 
        disconnect, 
        sendUserMessage, 
        interrupt,
        clearMessages
    } = useAnamQaSession({ personaId });

    // Connect automatically on mount in QA mode
    useEffect(() => {
        if (connectionState === 'idle') {
            connect('qa-persona-video');
        }
        return () => {
            disconnect();
        };
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [personaId]);

    const handleSend = async () => {
        if (!inputValue.trim() || connectionState !== 'streaming' || isSending) return;

        const textToSubmit = inputValue.trim();
        setIsSending(true);
        setInputValue(''); // Optimistic clear

        try {
            await sendUserMessage(textToSubmit);
        } finally {
            setIsSending(false);
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
            e.preventDefault();
            handleSend();
        }
    };

    return (
        <div 
            className="flex flex-col md:flex-row w-full h-full max-h-screen bg-black overflow-hidden font-sans"
            data-testid="qa-chat-root"
        >
            {/* LEFT SIDE: Video Player & Controls */}
            <div className="flex-1 md:w-1/2 flex flex-col p-4 border-r border-zinc-800">
                <div className="flex items-center justify-between mb-4">
                    <div>
                        <h2 className="text-white font-bold tracking-tight">System Testing: {agentName}</h2>
                        <div className="flex items-center gap-2 mt-1">
                            <div className={`w-2 h-2 rounded-full ${
                                connectionState === 'streaming' ? 'bg-green-500 animate-pulse' :
                                connectionState === 'connecting' ? 'bg-yellow-500 animate-pulse' :
                                connectionState === 'error' ? 'bg-red-500' : 'bg-zinc-600'
                            }`} />
                            <span 
                                className="text-xs text-zinc-400 font-mono uppercase tracking-wider"
                                data-testid="qa-connection-state"
                            >
                                {connectionState}
                            </span>
                        </div>
                    </div>
                    <div className="bg-red-900/40 text-red-400 border border-red-900 px-3 py-1 rounded text-xs font-bold uppercase tracking-widest">
                        QA MODE ENABLED
                    </div>
                </div>

                <div className="relative w-full aspect-video bg-zinc-900 rounded-lg overflow-hidden border border-zinc-800 flex items-center justify-center">
                     <video
                        id="qa-persona-video"
                        autoPlay
                        playsInline
                        className={`w-full h-full object-contain transition-opacity duration-300 ${connectionState === 'streaming' ? 'opacity-100' : 'opacity-0'}`}
                    />
                    {connectionState === 'connecting' && (
                        <div className="absolute inset-0 flex items-center justify-center bg-zinc-950/80">
                            <div className="w-8 h-8 border-2 border-zinc-600 border-t-zinc-200 rounded-full animate-spin" />
                        </div>
                    )}
                </div>

                <div className="mt-6 grid grid-cols-2 gap-3">
                    <button
                        onClick={() => connectionState === 'streaming' ? disconnect() : connect('qa-persona-video')}
                        className={`flex items-center justify-center gap-2 px-4 py-2 rounded font-semibold text-sm transition-colors ${
                            connectionState === 'streaming' 
                                ? 'bg-red-600/20 text-red-500 hover:bg-red-600/30' 
                                : 'bg-green-600/20 text-green-500 hover:bg-green-600/30'
                        }`}
                    >
                        <Square size={16} />
                        {connectionState === 'streaming' ? 'End Session' : 'Start Session'}
                    </button>

                    <button
                        onClick={interrupt}
                        disabled={connectionState !== 'streaming'}
                        title="Interrupt Persona Speaking"
                        data-testid="qa-interrupt"
                        className="flex items-center justify-center gap-2 px-4 py-2 rounded font-semibold text-sm transition-colors bg-orange-600/20 text-orange-500 hover:bg-orange-600/30 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        <Hand size={16} />
                        Interrupt
                    </button>
                </div>

                <div className="mt-4 p-4 bg-yellow-950/20 border border-yellow-900/50 rounded-md">
                   <p className="text-yellow-600/80 text-xs font-mono leading-relaxed">
                       <strong>NOTE:</strong> Microphone capture is disabled at the SDK level setting <code>disableInputAudio: true</code>. Use the chat panel to interact.
                   </p>
                </div>
            </div>

            {/* RIGHT SIDE: Chat & Transcript */}
            <div className="flex-1 md:w-1/2 flex flex-col p-4 bg-zinc-950">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="text-zinc-300 font-semibold text-sm uppercase tracking-widest">Transcript Log</h3>
                    <button 
                         onClick={clearMessages}
                         data-testid="qa-clear"
                         className="text-zinc-500 hover:text-white transition-colors"
                         title="Clear Transcript UI"
                    >
                        <RefreshCcw size={16} />
                    </button>
                </div>

                <TranscriptPanel messages={messages} />

                <div className="mt-4 flex gap-2">
                    <input
                        type="text"
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        onKeyDown={handleKeyDown}
                        placeholder={connectionState === 'streaming' ? "Type message to simulate user input..." : "Wait for connection..."}
                        disabled={connectionState !== 'streaming' || isSending}
                        data-testid="qa-input"
                        className="flex-1 bg-zinc-900 border border-zinc-700 text-white rounded px-4 py-3 text-sm focus:outline-none focus:border-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed"
                        autoComplete="off"
                    />
                    <button
                        onClick={handleSend}
                        disabled={!inputValue.trim() || connectionState !== 'streaming' || isSending}
                        data-testid="qa-send"
                        className="bg-indigo-600 hover:bg-indigo-500 disabled:bg-zinc-800 disabled:text-zinc-600 text-white rounded px-6 py-3 flex items-center justify-center transition-colors"
                    >
                        <Send size={18} className={isSending ? 'animate-pulse' : ''} />
                    </button>
                </div>
            </div>
        </div>
    );
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { createClient, AnamClient, AnamEvent, MessageStreamEvent } from '@anam-ai/js-sdk';

export type TranscriptMessage = {
    role: 'user' | 'agent' | 'system' | 'error';
    content: string;
    id: string;
};

interface UseAnamQaSessionProps {
    personaId: string;
}

export function useAnamQaSession({ personaId }: UseAnamQaSessionProps) {
    const [client, setClient] = useState<AnamClient | null>(null);
    const [connectionState, setConnectionState] = useState<'idle' | 'connecting' | 'streaming' | 'error'>('idle');
    const [messages, setMessages] = useState<TranscriptMessage[]>([]);
    const [sessionId, setSessionId] = useState<string | null>(null);

    // We use refs to handle live streaming chunks without causing excessive re-renders
    const currentMessageRef = useRef<string>('');
    const currentRoleRef = useRef<string>('');
    const isMounted = useRef(true);

    const appendMessage = useCallback((role: TranscriptMessage['role'], content: string) => {
        setMessages(prev => [...prev, { role, content, id: crypto.randomUUID() }]);
    }, []);

    const connect = useCallback(async (videoElementId: string) => {
        if (!personaId) return;

        setConnectionState('connecting');
        appendMessage('system', 'Initializing QA Session (Audio Input Disabled)...');

        try {
            // 1. Fetch Session Token
            const tokenRes = await fetch('/api/anam-token', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ personaId }),
            });

            if (!tokenRes.ok) throw new Error('Failed to fetch session token');
            const { sessionToken } = await tokenRes.json();

            if (!isMounted.current) return;

            // 2. Initialize Anam Client with QA settings
            const anamClient = createClient(sessionToken, { 
                disableInputAudio: true // CRITICAL: Prevents mic permission prompt
            });

            // Set up event listeners BEFORE connecting
            anamClient.addListener(AnamEvent.CONNECTION_ESTABLISHED, () => {
                if (!isMounted.current) return;
                setConnectionState('streaming');
                appendMessage('system', 'Neural Link Established. Streaming ready.');
                // Note: The Anam JS SDK does not expose sessionId synchronously here easily, 
                // but we track it conceptually if an event provides it later.
            });

            // Capture live conversation chunks
            anamClient.addListener(AnamEvent.MESSAGE_STREAM_EVENT_RECEIVED, (messageEvent: MessageStreamEvent) => {
                // If role changes, flush the previous message to state
                if (messageEvent.role !== currentRoleRef.current && currentRoleRef.current) {
                    if (currentMessageRef.current) {
                        appendMessage(currentRoleRef.current as 'user' | 'agent', currentMessageRef.current.trim());
                    }
                    currentMessageRef.current = '';
                }

                currentRoleRef.current = messageEvent.role;
                currentMessageRef.current += messageEvent.content;

                if (messageEvent.endOfSpeech) {
                    if (currentMessageRef.current) {
                        appendMessage(messageEvent.role as 'user' | 'agent', currentMessageRef.current.trim());
                    }
                    currentMessageRef.current = '';
                    currentRoleRef.current = '';
                }
            });

            anamClient.addListener(AnamEvent.CONNECTION_CLOSED, () => {
                if (!isMounted.current) return;
                setConnectionState('idle');
                appendMessage('system', 'Session disconnected.');

                // Flush remaining chunks
                if (currentMessageRef.current && currentRoleRef.current) {
                    appendMessage(currentRoleRef.current as 'user' | 'agent', currentMessageRef.current.trim());
                    currentMessageRef.current = '';
                    currentRoleRef.current = '';
                }
            });

            // 3. Connect and Stream directly to the video element
            await anamClient.streamToVideoElement(videoElementId);

            if (isMounted.current) {
                setClient(anamClient);
            }

        } catch (err) {
            console.error('Anam QA Initialization Error:', err);
            if (isMounted.current) {
                setConnectionState('error');
                appendMessage('error', 'Failed to connect to the agent. Check console.');
            }
        }
    }, [personaId, appendMessage]);

    const disconnect = useCallback(async () => {
        if (client) {
            appendMessage('system', 'Disconnecting...');
            await client.stopStreaming().catch(console.error);
            setClient(null);
            setConnectionState('idle');
        }
    }, [client, appendMessage]);

    const sendUserMessage = useCallback(async (text: string) => {
        if (!client || connectionState !== 'streaming') {
            appendMessage('error', 'Cannot send message: Not connected.');
            return;
        }
        if (!text.trim()) return;

        // Manually append the user's text to the transcript UI 
        // because sendUserMessage does not echo it back via events in text mode
        appendMessage('user', text.trim());

        try {
            await client.sendUserMessage(text.trim());
        } catch (err) {
            console.error('Failed to send text:', err);
            appendMessage('error', 'Failed to send message to Anam engine.');
        }
    }, [client, connectionState, appendMessage]);

    const interrupt = useCallback(() => {
        if (!client || connectionState !== 'streaming') return;
        client.interruptPersona();
        appendMessage('system', 'Persona interrupted.');
    }, [client, connectionState, appendMessage]);

    const clearMessages = useCallback(() => {
        setMessages([]);
    }, []);

    useEffect(() => {
        isMounted.current = true;
        return () => {
            isMounted.current = false;
        };
    }, []);

    return {
        client,
        connectionState,
        messages,
        sessionId,
        connect,
        disconnect,
        sendUserMessage,
        interrupt,
        clearMessages
    };
}

